import type { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import type { Resolvable } from '@ai-sdk/provider-utils';
import {
  FetchFunction,
  combineHeaders,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  lazySchema,
  parseProviderOptions,
  postJsonToApi,
  resolve,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import {
  PixelArtImageModelId,
  modelMaxImagesPerCall,
} from './pixelart-image-settings';

export interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers?: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';

  get maxImagesPerCall(): number {
    return modelMaxImagesPerCall[this.modelId] ?? 1;
  }

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
    headers,
    abortSignal,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const warnings: Array<SharedV3Warning> = [];

    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'PixelArt does not support aspectRatio. Use the size provider option instead.',
      });
    }

    const pixelartOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelartImageModelOptionsSchema,
    });

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    const body: Record<string, unknown> = {
      model: this.modelId,
      prompt,
      n,
      ...(size != null && { size }),
      ...(seed != null && { seed }),
      ...(pixelartOptions?.size != null && { size: pixelartOptions.size }),
      ...(pixelartOptions?.style != null && { style: pixelartOptions.style }),
      ...(pixelartOptions?.pixelDensity != null && {
        pixel_density: pixelartOptions.pixelDensity,
      }),
    };

    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generations`,
      headers: combineHeaders(
        await resolve(this.config.headers),
        headers,
      ),
      body,
      failedResponseHandler: pixelartFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        pixelartImageResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.data.map(item => item.b64_json),
      warnings,
      providerMetadata: {
        pixelart: {
          images: response.data.map(item => ({
            ...(item.style != null && { style: item.style }),
            ...(item.seed != null && { seed: item.seed }),
          })),
        },
      },
      response: {
        timestamp: currentDate,
        modelId: this.modelId,
        headers: responseHeaders,
      },
    };
  }
}

/**
 * Schema for PixelArt provider options passed via `providerOptions.pixelart`.
 */
export const pixelartImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z.object({
      /**
       * The size of the generated image (e.g. "512x512", "1024x1024").
       */
      size: z.string().optional(),

      /**
       * The visual style of the generated image.
       */
      style: z.enum(['pixel', 'retro', '8bit']).optional(),

      /**
       * The pixel density of the generated image.
       * Higher values produce more detailed pixel art.
       */
      pixelDensity: z.number().optional(),
    }),
  ),
);

export type PixelArtImageModelOptions = {
  /**
   * The size of the generated image (e.g. "512x512", "1024x1024").
   */
  size?: string;

  /**
   * The visual style of the generated image.
   */
  style?: 'pixel' | 'retro' | '8bit';

  /**
   * The pixel density of the generated image.
   */
  pixelDensity?: number;
};

const pixelartImageResponseSchema = z.object({
  data: z.array(
    z.object({
      b64_json: z.string(),
      style: z.string().nullish(),
      seed: z.number().nullish(),
    }),
  ),
});

const pixelartErrorSchema = z.object({
  error: z
    .object({
      message: z.string().optional(),
      type: z.string().optional(),
      code: z.string().optional(),
    })
    .optional(),
});

const pixelartFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: pixelartErrorSchema,
  errorToMessage: error => {
    if (
      typeof error === 'object' &&
      error != null &&
      'error' in error &&
      typeof (error as { error?: { message?: string } }).error?.message ===
        'string'
    ) {
      return (error as { error: { message: string } }).error.message;
    }
    return 'Unknown PixelArt error';
  },
});

/**
 * PixelArt image model IDs.
 */
export type PixelArtImageModelId =
  | 'pixelart-standard'
  | 'pixelart-hd'
  | (string & {});

/**
 * Style options for PixelArt image generation.
 */
export type PixelArtStyle = 'pixel' | 'retro' | '8bit';

/**
 * Settings for the PixelArt image model.
 */
export interface PixelArtImageSettings {
  /**
   * The size of the generated image (e.g. "512x512", "1024x1024").
   */
  size?: string;

  /**
   * The visual style of the generated image.
   * - "pixel": Classic pixel art style
   * - "retro": Retro gaming aesthetic
   * - "8bit": 8-bit era inspired style
   */
  style?: PixelArtStyle;

  /**
   * The pixel density of the generated image.
   * Higher values produce more detailed pixel art.
   */
  pixelDensity?: number;
}

/**
 * Maximum images per call for each model.
 */
export const modelMaxImagesPerCall: Record<string, number> = {
  'pixelart-standard': 4,
  'pixelart-hd': 2,
};
